import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine(); // Read the entire line instead of just a single word

        int maxLength = 10; // Define maximum length for input
        if (userInput.length() > maxLength) {
            System.out.println("Input string exceeds maximum length of " + maxLength);
            return;
        }

        char[] buffer = new char[maxLength];
        userInput.getChars(0, Math.min(userInput.length(), maxLength), buffer, 0); // Copy only up to maxLength characters

        System.out.println("Buffer content: " + String.valueOf(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
